sections.body:
$$
\boxed{\text{\textbf{수동부호규약}}(\text{passive sign convention})}
$$

$$
\text{\textbf{전류가 + 단자로 들어가면}} \;\Longrightarrow\; p = vi > 0 \;\Longrightarrow\; \text{\textbf{소비}}
$$

$$
\text{\textbf{전류가 + 단자에서 나오면}} \;\Longrightarrow\; p < 0 \;\Longrightarrow\; \text{\textbf{공급}}
$$

### 왜 규약이 필요한가

$$
\text{\textbf{전류의 방향과 전압의 극성을 미리 정해 놓지 않으면}} \;\Longrightarrow\; \text{부호가 뒤죽박죽}
$$

$$
\text{\textbf{일단 정하고 풀면}} \;\Longrightarrow\; \text{답이 음수면 \textbf{반대 방향}}\text{이라는 뜻}
$$

$$
\boxed{\text{\textbf{방향을 틀리게 잡아도 된다}} \;-\; \text{부호가 알려준다}}
$$

**이게 회로 해석의 자유**다. 미리 방향을 알 필요가 없다.

$$
\text{\textbf{다만 일관되게}} \;-\; \text{한 소자에 두 규약을 섞으면 틀린다}
$$

### 전력 수지

$$
\sum p = 0 \;-\; \text{\textbf{공급 = 소비}}
$$

$$
\text{\textbf{텔레겐의 정리}} \;-\; \text{회로 전체의 전력 합은 0}
$$

$$
\text{\textbf{에너지 보존}}\text{의 회로 버전} \;-\; \text{검산에 쓴다}
$$

### 전지의 접속

$$
\text{\textbf{직렬 } n \text{ 개}}: E = nE_0, \quad r = nr_0 \;\Longrightarrow\; I = \dfrac{nE_0}{R + nr_0}
$$

$$
\text{\textbf{병렬 } m \text{ 개}}: E = E_0, \quad r = \dfrac{r_0}{m} \;\Longrightarrow\; I = \dfrac{E_0}{R + \frac{r_0}{m}}
$$

$$
\text{\textbf{직렬 } n \text{ 개, 병렬 } m \text{ 개}}: I = \dfrac{nE_0}{R + \frac{n r_0}{m}}
$$

$$
\text{\textbf{직렬은 전압을, 병렬은 전류를}} \;-\; \text{용량을 늘리는 두 방향}
$$

### 줄열과 전력

$$
P = VI = I^2R = \dfrac{V^2}{R}\ \mathrm{[W]}
$$

$$
W = Pt\ \mathrm{[J]} = 0.24\,Pt\ \mathrm{[cal]}
$$

$$
\boxed{1\ \mathrm{J} = 0.24\ \mathrm{cal}, \qquad 1\ \mathrm{cal} = 4.2\ \mathrm{J}}
$$

$$
1\ \mathrm{kWh} = 860\ \mathrm{kcal}
$$

$$
\text{\textbf{860}} \;-\; \text{계산 문제에 자주}
$$

### 어느 식을 쓰나

$$
\text{\textbf{직렬}}\text{이면 전류가 같으니} \;\Longrightarrow\; P = I^2R \;\Longrightarrow\; \text{\textbf{큰 저항이 더 뜨겁다}}
$$

$$
\text{\textbf{병렬}}\text{이면 전압이 같으니} \;\Longrightarrow\; P = \dfrac{V^2}{R} \;\Longrightarrow\; \text{\textbf{작은 저항이 더 뜨겁다}}
$$

$$
\boxed{\text{\textbf{결선에 따라 정반대}}}
$$

**시험 단골**이다. 같은 두 저항인데 직렬이냐 병렬이냐로 답이 뒤집힌다.

$$
\text{\textbf{무엇이 같은지}}\text{부터 보고 식을 고른다}
$$

### 역회로

$$
\boxed{Z_1 Z_2 = K^2 \;(\text{\textbf{상수}})}
$$

$$
\text{\textbf{두 회로가 서로 역}}\text{이 되는 관계}
$$

$$
\text{\textbf{L과 C를 바꾸면}} \;\Longrightarrow\; \text{역회로가 된다}
$$

$$
Z_L = j\omega L, \quad Z_C = \dfrac{1}{j\omega C} \;\Longrightarrow\; Z_LZ_C = \dfrac{L}{C} = \text{\textbf{상수}}
$$

$$
\boxed{\dfrac{L}{C} = K^2} \;-\; \text{\textbf{주파수가 약분된다}}
$$

$$
\textbf{직렬 공진} \leftrightarrow \textbf{병렬 공진} \;-\; \text{서로 역회로}
$$

$$
\text{\textbf{필터 설계}}\text{에서 저역통과 ↔ 고역통과 변환에}
$$

### 정저항회로

$$
\boxed{Z_1Z_2 = R^2 \;\Longrightarrow\; Z_{in} = R \;(\text{\textbf{주파수 무관}})}
$$

$$
\text{\textbf{주파수가 변해도 저항이 일정}}
$$

$$
\text{\textbf{L과 C가 있는데도 순저항으로 보인다}}
$$

$$
\text{\textbf{역회로 조건}} + \; K = R \;\Longrightarrow\; \text{\textbf{정저항}}
$$

$$
\sqrt{\dfrac{L}{C}} = R \;\Longrightarrow\; \boxed{R = \sqrt{\dfrac{L}{C}}}
$$

$$
\text{\textbf{ct.1.8의 무손실 선로 특성 임피던스}}\text{와 같은 꼴}
$$

$$
\text{\textbf{감쇠기・등화기}}\text{에 쓴다} \;-\; \text{임피던스는 그대로 두고 신호만 조절}
$$

$$
\boxed{\text{\textbf{끝이 없으면}} \;\Longrightarrow\; \text{\textbf{반사가 없다}}}
$$

$$
V^- = 0 \;\Longrightarrow\; V(x) = V^+e^{-\gamma x}
$$

$$
\boxed{Z_{in} = Z_0} \;-\; \text{\textbf{입력 임피던스가 특성 임피던스}}
$$

$$
\text{\textbf{끝이 없으니 돌아올 게 없다}}
$$

### 무한장과 같아지는 법

$$
\boxed{Z_L = Z_0 \;\Longrightarrow\; \text{\textbf{정합}}}
$$

$$
\textbf{끝에 } \text{ Z} _0 \text{ 를 달면} \;\Longrightarrow\; \text{\textbf{선로는 무한한 줄 안다}}
$$

$$
\text{\textbf{반사가 없다}} \;-\; \text{에너지가 다 부하로}
$$

**통신에서 정합이 중요한 이유**다. 반사가 있으면 신호가 겹쳐 일그러진다.

$$
\text{\textbf{ct.1.7의 영상 임피던스 정합}}\text{과 같은 개념}
$$

$$
\boxed{|s\mathbf{I} - \mathbf{A}| = 0}
$$

$$
\text{\textbf{A의 고유값}}\text{이 곧 \textbf{극}}
$$

$$
\text{\textbf{ct.2.2의 } 1 + GH = 0}\text{ 과 같은 것}
$$

$$
G(s) = \dfrac{\mathbf{C}\,\text{adj}(s\mathbf{I}-\mathbf{A})\,\mathbf{B}}{|s\mathbf{I}-\mathbf{A}|} + \mathbf{D}
$$

$$
\textbf{분모가 } \text{ |s} \mathbf{I} \text{-} \mathbf{A} \text{|} \;\Longrightarrow\; \text{\textbf{극이 고유값}}
$$

$$
\boxed{\text{\textbf{고유값이 좌반면에 있으면 안정}}}
$$

$$
\text{\textbf{ct.2.5의 안정도}}\text{를 행렬로 판정}
$$

$$
\text{\textbf{라우스-후르비츠}}\text{를 } |s\mathbf{I}-\mathbf{A}| \text{ 에 적용하면 된다}
$$

$$
\boxed{
\begin{aligned}
K_p &= \lim_{s\to0}G(s)H(s) &\;(\text{\textbf{위치}}) \\
K_v &= \lim_{s\to0}sG(s)H(s) &\;(\text{\textbf{속도}}) \\
K_a &= \lim_{s\to0}s^2G(s)H(s) &\;(\text{\textbf{가속도}})
\end{aligned}
}
$$

$$
\text{\textbf{$s$ 가 하나씩 더 붙는다}}
$$

$$
\boxed{
\begin{aligned}
e_p &= \dfrac{1}{1+K_p} &\;(\text{\textbf{계단 입력}}) \\
e_v &= \dfrac{1}{K_v} &\;(\text{\textbf{램프 입력}}) \\
e_a &= \dfrac{1}{K_a} &\;(\text{\textbf{포물선 입력}})
\end{aligned}
}
$$

$$
\boxed{\text{\textbf{위치만 } 1+ \text{ 가 붙는다}}}
$$

$$
\text{\textbf{시험 함정}} \;-\; e_v = \frac{1}{1+K_v} \text{ 로 쓰면 틀린다}
$$

### 왜 위치만 다른가

$$
\text{\textbf{계단 입력}}: R(s) = \dfrac{1}{s}
$$

$$
e_p = \lim_{s\to0}\dfrac{s \cdot \frac{1}{s}}{1+GH} = \dfrac{1}{1 + \lim_{s\to0}GH} = \dfrac{1}{1+K_p}
$$

$$
\text{\textbf{램프 입력}}: R(s) = \dfrac{1}{s^2}
$$

$$
e_v = \lim_{s\to0}\dfrac{s\cdot\frac{1}{s^2}}{1+GH} = \lim_{s\to0}\dfrac{1}{s(1+GH)} = \lim_{s\to0}\dfrac{1}{s + sGH}
$$

$$
s \to 0 \;\Longrightarrow\; \text{\textbf{앞의 } s \text{ 가 사라진다}} \;\Longrightarrow\; \dfrac{1}{\lim sGH} = \dfrac{1}{K_v}
$$

$$
\boxed{\text{\textbf{$s$ 가 붙어 있어서 } 1 \text{ 이 사라진다}}}
$$

$$
\text{\textbf{외우지 말고 유도하면}} \text{ 헷갈릴 일이 없다}
$$

$$
\boxed{\textbf{이득 } \text{ K } \text{ 를 0에서 } \infty \text{ 로 바꿀 때 } \textbf{극의 자취}}
$$

$$
1 + KG_1H_1 = 0 \;-\; \text{\textbf{K가 변하면 근도 변한다}}
$$

$$
\text{\textbf{ct.2.5가 "안정한가"}}\text{를 물었다면}
$$

$$
\boxed{\text{\textbf{근궤적은 "K를 얼마로 하면 되나"}}\text{를 답한다}}
$$

$$
\text{\textbf{설계 도구}} \;-\; \text{판정이 아니라}
$$

### 왜 필요한가

$$
\text{\textbf{ct.2.4}}: K \uparrow \;\Longrightarrow\; \text{\textbf{정확}}\text{해진다}
$$

$$
\text{\textbf{ct.2.5}}: K \uparrow \;\Longrightarrow\; \text{\textbf{불안정}}\text{해진다}
$$

$$
\boxed{\text{\textbf{그 사이 어딘가}}\text{에 답이 있다}}
$$

$$
\text{\textbf{K를 바꾸며 극이 어디로 가나}}\text{를 보면 고를 수 있다}
$$

$$
\text{\textbf{원하는 극 배치가 안 나오면}} \;\Longrightarrow\; \text{\textbf{보상기}}\text{를 넣는다}
$$

$$
\boxed{\text{\textbf{극・영점을 추가해 궤적을 끌어온다}}}
$$

$$
\text{\textbf{K만으로는 궤적 위에서만} 고를 수 있다}
$$

$$
\text{\textbf{궤적 자체를 바꾸려면}} \;\Longrightarrow\; \text{보상}
$$

$$
\text{\textbf{컴퓨터는 연속을 모른다}}
$$

$$
\text{\textbf{띄엄띄엄 재고 띄엄띄엄 조작}}\text{한다}
$$

$$
\boxed{\text{\textbf{이산 시간}}(\text{discrete-time})}
$$

$$
\text{\textbf{ct.2.1의 신호에 의한 분류}}\text{에서 \textbf{이산}}\text{이 이것}
$$

$$
\text{\textbf{요즘 제어기는 다 디지털}} \;-\; \text{PLC ・ 마이크로프로세서 ・ DSP}
$$

$$
\text{\textbf{mc.7.5의 디지털 계전기}}\text{도 이 위에 서 있다}
$$

$$
\boxed{\text{\textbf{연속 이론을 그대로 못 쓴다}}}
$$

$$
\text{\textbf{라플라스}}(\text{ct.1.9})\text{ 대신 \textbf{z 변환}}
$$

$$
\text{\textbf{시간에 따른 ON/OFF}}\text{를 그린다}
$$

$$
\text{\textbf{순서와 타이밍}}\text{을 한눈에}
$$

$$
\text{\textbf{시퀀스 설계의 출발점}} \;-\; \text{원하는 동작을 먼저 그리고 회로를 짠다}
$$

$$
\boxed{
\begin{aligned}
\text{\textbf{저압}} &: \text{교류 } \mathbf{1\ kV}, \text{ 직류 } \mathbf{1.5\ kV} \text{ 이하} \\
\text{\textbf{고압}} &: \sim \mathbf{7\ kV} \\
\text{\textbf{특고압}} &: \mathbf{7\ kV} \text{ 초과}
\end{aligned}
}
$$

| | 무엇 |
|---|---|
| **기술기준** | 성능 (목표) |
| **KEC** | 방법 (수단) |

$$
\boxed{\text{\textbf{기본보호} = 직접접촉}, \qquad \text{\textbf{고장보호} = 간접접촉}}
$$

$$
\text{\textbf{안전을 위한 보호 여섯}}: \text{감전 ・ 열 ・ 과전류 ・ 고장전류 ・ 전압외란 ・ 전원중단}
$$

$$
\text{\textbf{KEC의 정신}} \;-\; \text{\textbf{IEC 국제 표준}}\text{에 맞추기}
$$

> KEC **113**

$$
\boxed{
\begin{array}{c|l}
\mathbf{113.2} & \textbf{감전} \\
\mathbf{113.3} & \textbf{열 영향} \\
\mathbf{113.4} & \textbf{과전류} \\
\mathbf{113.5} & \textbf{고장전류} \\
\mathbf{113.6} & \textbf{전압외란 ・ 전자기 장애} \\
\mathbf{113.7} & \textbf{전원공급 중단}
\end{array}
}
$$

$$
\text{\textbf{여섯 가지가 서로 다른 사고}}\text{를 막는다}
$$

### 일반 사항 (113.1)

$$
\text{\textbf{위험과 장애로부터 인축 및 재산}}\text{을 안전하게}
$$

$$
\text{\textbf{가축의 안전}}\text{을 위한 요구사항은 \textbf{가축을 사육하는 장소}}\text{에 적용}
$$

$$
\boxed{
\begin{array}{c|l|l}
\mathbf{113.2} & \textbf{감전} & \text{기본보호 + 고장보호} \\
\mathbf{113.3} & \textbf{열} & \text{화재 + 화상} \\
\mathbf{113.4} & \textbf{과전류} & \text{과부하 + 단락} \\
\mathbf{113.5} & \textbf{고장전류} & \text{\textbf{허용온도}} \\
\mathbf{113.6} & \textbf{전압외란・EMC} & \text{저전압 ・ 복전 ・ 전자기} \\
\mathbf{113.7} & \textbf{전원중단} & \text{정전이 위험한 곳}
\end{array}
}
$$

$$
\boxed{\text{\textbf{과전류는 끊는 쪽, 고장전류는 버티는 쪽}}}
$$

$$
\text{\textbf{보호 = 크기 제한 또는 시간 제한}} \;-\; \text{전류 × 시간이 위험이니}
$$

$$
\boxed{
\begin{array}{c|c}
\mathbf{L1} & \textbf{갈색} \\
\mathbf{L2} & \textbf{검은색} \\
\mathbf{L3} & \textbf{회색} \\
\mathbf{N} & \textbf{파란색} \\
\textbf{PE} & \textbf{녹색-노란색}
\end{array}
} \qquad \text{\textbf{"갈흑회파녹노"}}
$$

| 접속 | 규정 |
|---|---|
| **세기** | **20% 이상 감소 금지** (= 80% 이상 유지) |
| **저항** | **증가시키지 말 것** (대원칙) |
| **병렬** | **구리 50㎟ · 알루미늄 70㎟** 이상, 같은 것끼리 |
| **다른 금속** | **전기적 부식** 방지 |
| **캡타이어** | $10\ \mathrm{mm^2}$ 이상이면 예외 |

$$
\text{\textbf{색상표가 이 단원의 전부}} \;-\; \text{옛 기준과 하나도 안 맞으니 반드시 새로}
$$

> KEC **135**

$$
\text{\textbf{표 135-1}}\text{에 따라} \;-\; \text{132와 비슷한 구조}
$$

$$
\text{\textbf{권선마다}} \;-\; \text{1차・2차・3차를 따로}
$$

$$
\text{\textbf{mc.4.9의 변압기 시험}}\text{이 이것}
$$

> KEC **136**

$$
\text{\textbf{개폐기 ・ 차단기 ・ 계기용변성기}} \text{ 등}
$$

$$
\text{\textbf{mc.4.10의 PT・CT}}\text{도 여기}
$$

$$
\text{\textbf{mc.7.6의 절연내력 시험}}\text{의 근거}
$$

$$
\boxed{
\begin{array}{c|l|l}
\text{\textbf{제1문자}} & \text{\textbf{전원계통과 대지}} & \mathbf{T} \text{ 직접접속} \;/\; \mathbf{I} \text{ 절연・고임피던스} \\
\text{\textbf{제2문자}} & \text{\textbf{노출도전부와 대지}} & \mathbf{T} \text{ 독립 접지극} \;/\; \mathbf{N} \text{ 전원 접지점에} \\
\text{\textbf{제3문자}} & \text{\textbf{중성선과 보호도체}} & \mathbf{S} \text{ 별도} \;/\; \mathbf{C} \text{ 겸용}(\text{PEN})
\end{array}
}
$$

$$
\text{\textbf{순서를 외우면 나머지는 저절로}}
$$

### 제1문자 — 전원

$$
\mathbf{T} \;(\text{Terra}, \text{대지}) \;-\; \text{\textbf{한 점을 대지에 직접 접속}}
$$

$$
\mathbf{I} \;(\text{Isolated}) \;-\; \text{\textbf{모든 충전부를 절연}} \text{ 또는 } \text{\textbf{높은 임피던스}}\text{를 통해 접속}
$$

$$
\boxed{\text{\textbf{I는 완전 절연만이 아니다}}} \;-\; \text{고임피던스 접지도 I}
$$

$$
\text{\textbf{시험 함정}}
$$

**pw.4.1의 비접지·소호리액터 접지**가 IT에 해당한다. 거기서 "지락전류를 작게"라고
한 그 사상이다.

### 제2문자 — 노출도전부

$$
\mathbf{T} \;-\; \text{\textbf{대지로 직접 접속}}, \text{ \textbf{전원계통의 접지와는 무관}}
$$

$$
\mathbf{N} \;-\; \text{\textbf{전원계통의 접지점}}\text{에 직접 접속}
$$

$$
\text{\textbf{통상 중성점}}, \text{ 중성점이 없으면 \textbf{선도체}}
$$

$$
\boxed{\text{\textbf{T는 따로, N은 함께}}}
$$

$$
\text{\textbf{"전원계통의 접지와는 무관"}}\text{이 T의 핵심}
$$

$$
\text{\textbf{독립된 접지극}} \;-\; \text{전원 쪽 접지극과 별개}
$$

### 제3문자 — 중성선과 보호도체

$$
\mathbf{S} \;(\text{Separated}) \;-\; \text{\textbf{별도의 도체}}
$$

$$
\mathbf{C} \;(\text{Combined}) \;-\; \text{\textbf{한 개의 도체로 겸용}}(\text{PEN})
$$

$$
\text{\textbf{TN에만 붙는다}} \;-\; \text{TT・IT는 애초에 노출도전부가 따로니}
$$

$$
\boxed{\text{\textbf{전원의 한 점을 직접 접지}}\text{하고}}
$$

$$
\boxed{\text{\textbf{노출도전부는 전원의 접지전극과 전기적으로 독립적인 접지극}}\text{에}}
$$

$$
\text{\textbf{두 접지극이 따로}} \;-\; \text{그래서 T-T}
$$

$$
